T681127 [语言月赛 202510] 下落模拟
题目链接
可以发现列与列之间是不影响的，对于每列从下往上扫，遇到箱子就把它放到“目前的最底下”，同时让“目前的最底下” −1-1−1；遇到挡板就将“目前的最底下”改为挡板 −1-1−1 即可。
代码：
/* * @FilePath: \c++\T681127.cpp * @Author: WRT_Partisan * @Date: 2025-10-17 19:24:02 */#include &lt;bits/stdc++.h&gt;using namespace std;#define int long longtypedef unsigned long long ull;int n, m, mp[100005][15], lst;string s;signed main()&#123;    cin.tie(0)-&gt;sync_with_stdio(0);    cin &gt;&gt; n &gt;&gt; m;    for (int i = 1; i &lt;= n; i++)    &#123;        cin &gt;&gt; s;        for (int j = 0; j &lt; s.size(); j++)        &#123;            if (s[j] == &#x27;.&#x27;)                mp[i][j + 1] = 0;            else if (s[j] == &#x27;-&#x27;)                mp[i][j + 1] = -1;            else                mp[i][j + 1] = s[j] - &#x27;A&#x27; + 1;        &#125;    &#125;    for (int j = 1; j &lt;= m; j++)    &#123;        lst = n;        for (int i = n; i &gt;= 1; i--)        &#123;            if (mp[i][j] &gt; 0)                swap(mp[i][j], mp[lst][j]), lst--;            else if (mp[i][j] &lt; 0)                lst = i - 1;        &#125;    &#125;    for (int i = 1; i &lt;= n; i++)    &#123;        for (int j = 1; j &lt;= m; j++)        &#123;            if (mp[i][j] == -1)                cout &lt;&lt; &quot;-&quot;;            else if (mp[i][j] == 0)                cout &lt;&lt; &quot;.&quot;;            else                cout &lt;&lt; (char)(mp[i][j] + &#x27;A&#x27; - 1);        &#125;        cout &lt;&lt; &quot;\n&quot;;    &#125;    return 0;&#125;

规范二分写法
// 这种写法修改左右边界的细节相同while (l &lt;= r)&#123; // 注意:小于等于号    int mid = (l + r) / 2;    if (check(mid))        l = mid + 1, ans = mid; // 当check成立时,应该能够完成任务    else        r = mid - 1; // 如果check成立时不能完成任务,那么在这里修改ans&#125;// 循环结束后ans即为所求答案
形如 while(l&lt;r) 的写法中，两个边界修改时的细节不同，不方便记忆，同时还存在一些难以描述的细节问题（虽然那个写法一般也是正确的）。

#include &lt;bits/stdc++.h&gt;using namespace std;#define int long longtypedef unsigned long long ull;int n, k, a[1000005];deque&lt;int&gt; q;signed main()&#123;    cin.tie(0)-&gt;sync_with_stdio(0);    cin &gt;&gt; n &gt;&gt; k;    for (int i = 1; i &lt;= n; i++)        cin &gt;&gt; a[i];    for (int i = 1; i &lt;= n; i++)    &#123;        while (!q.empty() &amp;&amp; q.front() + k &lt;= i)            q.pop_front();        while (!q.empty() &amp;&amp; a[q.back()] &gt;= a[i])            q.pop_back();        q.push_back(i);        if (i &gt;= k)            cout &lt;&lt; a[q.front()] &lt;&lt; &quot; &quot;;    &#125;    cout &lt;&lt; &quot;\n&quot;, q.clear();    for (int i = 1; i &lt;= n; i++)    &#123;        while (!q.empty() &amp;&amp; q.front() + k &lt;= i)            q.pop_front();        while (!q.empty() &amp;&amp; a[q.back()] &lt;= a[i])            q.pop_back();        q.push_back(i);        if (i &gt;= k)            cout &lt;&lt; a[q.front()] &lt;&lt; &quot; &quot;;    &#125;    return 0;&#125;
